function generateMockTimelineEvents() {
    const now = new Date();
    const events = [];
    // Generate events for the day
    const eventTemplates = [
        {
            type: 'meal',
            title: 'Breakfast',
            hours: 8
        },
        {
            type: 'medication',
            title: 'Morning Medication',
            hours: 8,
            minutes: 30
        },
        {
            type: 'hydration',
            title: 'Water Reminder',
            hours: 10
        },
        {
            type: 'activity',
            title: 'Light Exercise',
            hours: 10,
            minutes: 30
        },
        {
            type: 'location_change',
            title: 'Moved to Living Room',
            hours: 11
        },
        {
            type: 'meal',
            title: 'Lunch',
            hours: 12
        },
        {
            type: 'conversation',
            title: 'Conversation with Aegis',
            hours: 13
        },
        {
            type: 'medication',
            title: 'Afternoon Medication',
            hours: 14
        },
        {
            type: 'alert',
            title: 'Near Exit Detected',
            hours: 15,
            minutes: 30
        },
        {
            type: 'hydration',
            title: 'Water Reminder',
            hours: 16
        },
        {
            type: 'meal',
            title: 'Dinner',
            hours: 18
        },
        {
            type: 'activity',
            title: 'Evening Activity',
            hours: 19
        },
        {
            type: 'medication',
            title: 'Evening Medication',
            hours: 20
        },
        {
            type: 'sleep',
            title: 'Bedtime Routine Started',
            hours: 21
        }
    ];
    eventTemplates.forEach((template, i)=>{
        const timestamp = new Date(now);
        timestamp.setHours(template.hours, template.minutes || 0, 0, 0);
        // Only include past events
        if (timestamp <= now) {
            events.push({
                id: `event-${i}`,
                timestamp,
                type: template.type,
                title: template.title,
                status: Math.random() > 0.2 ? 'completed' : 'pending',
                description: template.type === 'alert' ? 'Gentle redirection provided' : undefined
            });
        }
    });
    return events;
}
